Effectively I didn't tested it before committing it. I just made a few tests and they show that the double loop as heavily better performance on arrays with duplicates but worst performance on arrays without duplicates. I found an other implementation with object and simple loop, here is my test code: 
``` ts
import _ from 'lodash';

function checkDuplicateDoubleLoop(list: any[]) {
  return (() => {
    for (let i = 0; i < list.length; i++) {
      const a = list[i];

      for (let j = 0; j < i; j++) {
        if (a === list[j]) {
          return false;
        }
      }
    }
    return true;
  })();
}

function checkDuplicateSet(list: any[]) {
  return new Set(list).size >= list.length;
}

function checkDuplicateObject(list: any[]) {
  return (() => {
    const obj: any = {};
    for (const elem of list) {
      if (obj[elem]) {
        return false;
      } else {
        obj[elem] = true;
      }
    }
    return true;
  })();
}

function checkDeepDuplicateDoubleLoop(list: any[]) {
  return (() => {
    for (let i = 0; i < list.length; i++) {
      const a = list[i];

      for (let j = 0; j < i; j++) {
        if (_.isEqual(a, list[j])) {
          return false;
        }
      }
    }
    return true;
  })();
}

function checkDeepDuplicateSet(list: any[]) {
  return new Set(list).size >= list.length;
}

(() => {
  const list = [];

  for (let i = 0; i < 10000000; i++) {
    list.push(i);
  }

  // commented because too long

  // console.time('noDupDoubleLoop');
  // console.log('noDupDoubleLoop: ', checkDuplicateDoubleLoop(list));
  // console.timeEnd('noDupDoubleLoop');

  console.log('noDupDoubleLoop: Too long');

  console.time('noDupSet');
  console.log('noDupSet: ', checkDuplicateSet(list));
  console.timeEnd('noDupSet');

  console.time('noDupObject');
  console.log('noDupObject: ', checkDuplicateObject(list));
  console.timeEnd('noDupObject');

  list.unshift(0);

  console.time('dupDoubleLoop');
  console.log('dupDoubleLoop: ', checkDuplicateDoubleLoop(list));
  console.timeEnd('dupDoubleLoop');

  console.time('dupSet');
  console.log('dupSet: ', checkDuplicateSet(list));
  console.timeEnd('dupSet');

  console.time('dupObject');
  console.log('dupObject: ', checkDuplicateObject(list));
  console.timeEnd('dupObject');
})();

(() => {
  const list = [];

  for (let i = 0; i < 10000; i++) {
    list.push({ i });
  }

  console.time('noDeepDupDoubleLoop');
  console.log('noDeepDupDoubleLoop: ', checkDeepDuplicateDoubleLoop(list));
  console.timeEnd('noDeepDupDoubleLoop');

  console.time('noDeepDupSet');
  console.log('noDeepDupSet: ', checkDuplicateSet(list));
  console.timeEnd('noDeepDupSet');

  console.time('noDeepDupObject');
  console.log('noDeepDupObject: ', checkDuplicateObject(list));
  console.timeEnd('noDeepDupObject');

  list.unshift({ i: 0 });

  console.time('deepDupDoubleLoop');
  console.log('deepDupDoubleLoop: ', checkDeepDuplicateDoubleLoop(list));
  console.timeEnd('deepDupDoubleLoop');

  console.time('deepDupSet');
  console.log('deepDupSet: ', checkDuplicateSet(list));
  console.timeEnd('deepDupSet');

  console.time('deepDupObject');
  console.log('deepDupObject: ', checkDuplicateObject(list));
  console.timeEnd('deepDupObject');
})();
```

